const studentName = $input.item.json.studentName;
const submission = $input.item.json.submissionText;

const prompt = `Provide formative feedback on this draft submission.

STUDENT: ${studentName}

SUBMISSION:
${submission}

EVALUATE AGAINST RUBRIC:
- Part 1: Customer Experience Analysis (35 pts)
- Part 2: Service Recovery Strategy (35 pts)
- Part 3: Resource-Constrained Proposal (30 pts)

Provide:
1. Brief feedback for each part (3-5 sentences)
2. Specific strengths (2-3 points)
3. Areas for improvement (2-3 points)
4. Next steps for revision

Return as JSON:
{
  "student_name": "${studentName}",
  "feedback": {
    "part1": "feedback text",
    "part2": "feedback text",
    "part3": "feedback text"
  },
  "strengths": ["point 1", "point 2"],
  "improvements": ["point 1", "point 2"],
  "next_steps": ["step 1", "step 2"]
}`;

return { json: { prompt, studentName } };

const response = $input.item.json.response;
const studentName = $node['Build Feedback Prompt'].json.studentName;

let feedback;
try {
  const clean = response.replace(/```json/g, '').replace(/```/g, '').trim();
  feedback = JSON.parse(clean);
} catch (e) {
  return { json: { error: 'Failed to parse AI response', raw: response } };
}

const formattedFeedback = `
FORMATIVE FEEDBACK REPORT
========================

Student: ${studentName}
Date: ${new Date().toLocaleDateString()}

This is AI-generated formative feedback to support your learning.
Use it to guide revision before submitting to your instructor.

--- PART 1: CUSTOMER EXPERIENCE ---
${feedback.feedback.part1}

--- PART 2: SERVICE RECOVERY ---
${feedback.feedback.part2}

--- PART 3: STRATEGY PROPOSAL ---
${feedback.feedback.part3}

--- YOUR STRENGTHS ---
${feedback.strengths.map((s, i) => `${i+1}. ${s}`).join('\n')}

--- AREAS TO DEVELOP ---
${feedback.improvements.map((s, i) => `${i+1}. ${s}`).join('\n')}

--- NEXT STEPS ---
${feedback.next_steps.map((s, i) => `${i+1}. ${s}`).join('\n')}

REMEMBER:
- This is formative feedback, not a grade
- You can request feedback multiple times
- Final grades are determined by your instructor
========================
`;

return { json: { feedback: formattedFeedback, studentName } };
